import React, { useEffect } from "react";
import "aos/dist/aos.css";
import AOS from "aos";

const projects = [
  {
    title: "Customer Discount Request",
    platform: "Shopware 6",
    domain: "Ecommerce",
    type: "Plugin",
    description: `Customer Discount Request plugin for Shopware 6 allows registered users to request a price discount for large number of products. Users can choose the quantity and the discount percentage for the preferred product. Shop owners or merchants can approve or reject a discount proposal for the product.`,
    link: "https://store.shopware.com/en/brand27683468217m/customer-discount-request.html",
  },
  {
    title: "Customer Membership Program",
    platform: "Shopware 6",
    domain: "Ecommerce",
    type: "Plugin",
    description: `Customer Membership Offer plugin for Shopware 6 allows you to categorize registered users under silver, gold and platinum plans. The shop admin can define the minimum purchase amount for each plan.`,
    link: "https://store.shopware.com/en/brand53235685891m/customer-membership-program.html"
  },
  {
    title: "Ticket System",
    platform: "Shopware 6",
    domain: "Ecommerce",
    type: "Plugin",
    description: `The Ticket System plugin allows you to create and manage events, sell tickets to those events. Users can choose the number of tickets they want and purchase them.`,
    link: "https://store.shopware.com/en/brand11399667561m/ticket-system.html"
  },
  {
    title: "Order Status Analytics",
    platform: "Shopware 6",
    domain: "Ecommerce",
    type: "Plugin",
    description: `Order Status Analytics plugin adds detailed insights and visuals to the order page. Customers can easily see the current status of their overall orders.`,
    link: "https://store.shopware.com/en/brand86225088288m/order-status-analytics.html"
  },
  {
    title: "Archive Portal",
    platform: "Node.js",
    domain: "Internal Drive",
    type: "Internal Project",
    description: `This project allows users to store uploaded files, and they can view, download, and delete files based on their user role. It is similar to Google Drive.`,
    keyFeatures: [
      "Dashboard module for Admin and Employee roles.",
      "Projects and Roles management.",
      "Secure file upload and access privilege system."
    ]
  },
  {
    title: "Geocoding API Integration",
    platform: "Odoo 17",
    domain: "Ticket Booking",
    type: "Client",
    description: `Developed a specialized module for Odoo 17 that utilizes the Google Geocoding API to dynamically display nearby events.`,
    keyFeatures: [
      "Location-Based Event Display.",
      "Integration with Google Geocoding API.",
      "Real-time event filtering and ticket booking."
    ]
  },
  {
    title: "Production Unit ERP",
    platform: "Laravel Framework",
    domain: "ERP",
    type: "Client",
    description: `A web-based Enterprise Resource Planning (ERP) software developed to manage various business activities within an organization.`,
    keyFeatures: [
      "Product Planning and Cost Estimation.",
      "Manufacturing and Service Delivery management.",
      "Inventory and Shipment automation."
    ]
  }
];

const Projects = () => {
  useEffect(() => {
    AOS.init({ duration: 1000, easing: "ease-in-out", once: true });
  }, []);

  return (
    <section id="projects" className="section">
      <div className="container section-title" data-aos="fade-up">
        <h2 className="text-gradient">Featured Projects</h2>
        <p>A showcase of my recent work across e-commerce, ERP systems, and custom plugin development.</p>
      </div>

      <div className="container">
        <div className="row g-4">
          {projects.map((project, index) => (
            <div key={index} className="col-lg-6 col-xl-4" data-aos="fade-up" data-aos-delay={index * 50}>
              <div className="project-card h-100">
                <div className="project-info d-flex flex-column h-100">
                  <div className="d-flex justify-content-between align-items-start mb-3">
                    <span className="badge glass-effect text-primary border-primary-glow px-3 py-2" style={{ borderRadius: '10px' }}>
                      {project.platform}
                    </span>
                    <span className="text-muted small">{project.type}</span>
                  </div>

                  <h4 className="mb-3">{project.title}</h4>
                  <p className="text-muted mb-4 small flex-grow-1">{project.description}</p>

                  {project.keyFeatures && (
                    <div className="mb-4">
                      <h6 className="text-gradient small fw-bold mb-2">Key Features:</h6>
                      <ul className="list-unstyled small text-muted">
                        {project.keyFeatures.map((feature, i) => (
                          <li key={i} className="mb-1"><i className="bi bi-patch-check-fill text-primary me-2"></i>{feature}</li>
                        ))}
                      </ul>
                    </div>
                  )}

                  <div className="mt-auto">
                    {project.link ? (
                      <a href={project.link} target="_blank" rel="noopener noreferrer" className="btn btn-custom w-100 btn-sm">
                        View Details <i className="bi bi-arrow-up-right-circle ms-1"></i>
                      </a>
                    ) : (
                      <button className="btn glass-effect w-100 btn-sm text-muted" disabled>
                        Private Project
                      </button>
                    )}
                  </div>
                </div>
              </div>
            </div>
          ))}
        </div>
      </div>
    </section>
  );
};

export default Projects;
